sql:
SELECT first_name || ' ' || last_name AS customer_full_name
FROM customers
ORDER BY customer_full_name;

external_knowledge:
- "detailed order and payment information" includes pending, completed, canceled, and returned orders, as well as payment counts and total payment amounts for each payment method;
- "loyalty program participation" refers to the customer's enrollment in a loyalty program, loyalty points, and customer segment (e.g., premium or regular);
- "ranking them by their total expenditure" implies sorting the results by the total amount spent in descending order.

sql:
SELECT order_id, order_date
FROM orders
ORDER BY order_date DESC;

SELECT order_date
FROM orders
ORDER BY order_date DESC;

SELECT status_name
FROM order_status
WHERE status_id = 1;
